import os

def write(path, content):
    parts = path.replace("\\", "/").split("/")
    if len(parts) > 1:
        folder = "/".join(parts[:-1])
        os.makedirs(folder, exist_ok=True)
    with open(path, "w") as f:
        f.write(content)

